/** Look a lens up by source NSID. Returns the first match (registration order). */
export function findLensBySource(sourceNsid: string): LensRegistryEntry | undefined {
  return lensRegistry.find((entry) => entry.sourceNsid === sourceNsid);
}

/** All distinct upstream NSID prefixes covered by the registry. */
export function lensSourcePrefixes(): readonly string[] {
  const prefixes = new Set<string>();
  for (const entry of lensRegistry) {
    const head = entry.sourceNsid.split('.').slice(0, 2).join('.');
    prefixes.add(head);
  }
  return Array.from(prefixes).sort();
}
